#include <stdio.h>

void swap(int *x, int *y) {
    int temp = *x;
    *x = *y;
    *y = temp;
}

int main() {
    int a, b;
    if (scanf("%d %d", &a, &b) != 2) return 0;
    swap(&a, &b);
    printf("%d %d\n", a, b);
    return 0;
}

